1	/**
2	 * SKF Uninstall Command
3	 * Clean removal of SKF files, IDE skill directories, sidecar, and output folders.
4	 * Uses the manifest to know exactly what to remove.
5	 */
6	
7	const chalk = require('chalk');
8	const path = require('node:path');
9	const fs = require('fs-extra');
10	const { confirm, isCancel, spinner, log, outro } = require('@clack/prompts');
11	const { readManifest, MANIFEST_DIR, MANIFEST_FILE } = require('../lib/manifest');
12	const { removeAllSkfSkills } = require('../lib/ide-skills');
13	
14	/**
15	 * Count files that still exist on disk from manifest lists.
16	 */
17	async function countExistingFiles(projectDir, manifest) {
18	  const allFiles = [
19	    ...(manifest.files.skf || []),
20	    ...(manifest.files.sidecar || []),
21	    ...(manifest.files.ide_skills || []),
22	    ...(manifest.files.learning || []),
23	    ...(manifest.files.output || []),
24	  ];
25	
26	  let existing = 0;
27	  for (const file of allFiles) {
28	    if (await fs.pathExists(path.join(projectDir, file))) {
29	      existing++;
30	    }
31	  }
32	  return { total: allFiles.length, existing };
33	}
34	
35	/**
36	 * Display what will be removed, grouped by category.
37	 */
38	async function displayRemovalPlan(projectDir, manifest) {
39	  const categories = [
40	    { key: 'skf', label: 'SKF module files', dir: manifest.skf_folder },
41	    { key: 'sidecar', label: 'Agent sidecar state', dir: '_bmad/_memory/forger-sidecar' },
42	    { key: 'ide_skills', label: 'IDE skill directories' },
43	    { key: 'learning', label: 'Learning material', dir: '_skf-learn' },
44	    { key: 'output', label: 'Output folder scaffolding' },
45	  ];
46	
47	  const lines = [];
48	  for (const cat of categories) {
49	    const files = manifest.files[cat.key] || [];
50	    if (files.length === 0) continue;
51	
52	    // Count how many still exist
53	    let existCount = 0;
54	    for (const f of files) {
55	      if (await fs.pathExists(path.join(projectDir, f))) existCount++;
56	    }
57	
58	    if (existCount === 0) continue;
59	
60	    if (cat.dir) {
61	      lines.push(`${chalk.red('×')} ${cat.label} ${chalk.dim(`(${cat.dir}/ — ${existCount} files)`)}`);
62	    } else {
63	      lines.push(`${chalk.red('×')} ${cat.label} ${chalk.dim(`(${existCount} files)`)}`);
64	    }
65	  }
66	
67	  // Manifest itself
68	  lines.push(`${chalk.red('×')} Installation manifest ${chalk.dim(`(${MANIFEST_DIR}/${MANIFEST_FILE})`)}`);
69	
70	  log.warn(`The following will be removed:\n${lines.join('\n')}`);
71	}
72	
73	/**
74	 * Remove files listed in the manifest, then clean empty parent directories.
75	 */
76	async function removeFiles(projectDir, fileList) {
77	  let removed = 0;
78	  for (const file of fileList) {
79	    const fullPath = path.join(projectDir, file);
80	    if (await fs.pathExists(fullPath)) {
81	      await fs.remove(fullPath);
82	      removed++;
83	    }
84	  }
85	  return removed;
86	}
87	
88	/**
89	 * Remove a directory if it exists and is empty (or force remove).
90	 */
91	async function removeEmptyDir(dirPath) {
92	  if (!(await fs.pathExists(dirPath))) return;
93	  try {
94	    const entries = await fs.readdir(dirPath);
95	    if (entries.length === 0) {
96	      await fs.remove(dirPath);
97	    }
98	  } catch {
99	    // ignore
100	  }
101	}
102	
103	module.exports = {
104	  command: 'uninstall',
105	  description: 'Remove SKF installation from the current project',
106	  options: [],
107	  action: async () => {
108	    try {
109	      const projectDir = process.cwd();
110	      const manifest = await readManifest(projectDir);
111	
112	      if (!manifest) {
113	        // Check if SKF exists without manifest
114	        const skfExists = await fs.pathExists(path.join(projectDir, '_bmad/skf'));
115	        if (skfExists) {
116	          log.warn(
117	            'No manifest found. Reinstall first to generate one,\nthen run uninstall again for clean removal.\nRun: npx bmad-module-skill-forge install',
118	          );
119	        } else {
120	          log.warn('SKF is not installed in this directory.');
121	        }
122	        process.exit(0);
123	        return;
124	      }
125	
126	      const { existing } = await countExistingFiles(projectDir, manifest);
127	      if (existing === 0) {
128	        log.warn('No SKF files found to remove.');
129	        // Clean up stale manifest
130	        await fs.remove(path.join(projectDir, MANIFEST_DIR, MANIFEST_FILE));
131	        process.exit(0);
132	        return;
133	      }
134	
135	      await displayRemovalPlan(projectDir, manifest);
136	
137	      const shouldProceed = await confirm({
138	        message: 'Proceed with uninstall?',
139	        initialValue: false,
140	      });
141	
142	      if (isCancel(shouldProceed) || !shouldProceed) {
143	        log.warn('Uninstall cancelled.');
144	        process.exit(0);
145	        return;
146	      }
147	
148	      const s = spinner();
149	
150	      // Remove IDE skill directories from all known platforms (skills + legacy command files)
151	      s.start('Removing IDE skill directories...');
152	      const removedIdeDirs = await removeAllSkfSkills(projectDir);
153	      if (removedIdeDirs.length > 0) {
154	        s.stop(`Cleaned skills from ${removedIdeDirs.length} IDE target(s)`);
155	      } else {
156	        s.stop('No IDE skill directories found');
157	      }
158	
159	      // Remove learning material directory
160	      const learnFiles = manifest.files.learning || [];
161	      if (learnFiles.length > 0) {
162	        s.start('Removing learning material...');
163	        const learnDir = path.join(projectDir, '_skf-learn');
164	        if (await fs.pathExists(learnDir)) {
165	          await fs.remove(learnDir);
166	        }
167	        s.stop('Learning material removed');
168	      }
169	
170	      // Remove output folder scaffolding (.gitkeep only)
171	      const outputFiles = manifest.files.output || [];
172	      if (outputFiles.length > 0) {
173	        s.start('Removing output scaffolding...');
174	        await removeFiles(projectDir, outputFiles);
175	        // Remove empty output folders
176	        for (const folder of [manifest.skills_output_folder, manifest.forge_data_folder]) {
177	          if (folder) {
178	            await removeEmptyDir(path.join(projectDir, folder));
179	          }
180	        }
181	        s.stop('Output scaffolding removed');
182	      }
183	
184	      // Remove sidecar
185	      s.start('Removing agent sidecar...');
186	      const sidecarDir = path.join(projectDir, '_bmad', '_memory', 'forger-sidecar');
187	      if (await fs.pathExists(sidecarDir)) {
188	        await fs.remove(sidecarDir);
189	      }
190	      await removeEmptyDir(path.join(projectDir, '_bmad', '_memory'));
191	      s.stop('Agent sidecar removed');
192	
193	      // Remove SKF module directory
194	      s.start('Removing SKF module...');
195	      const skfDir = path.join(projectDir, manifest.skf_folder);
196	      if (await fs.pathExists(skfDir)) {
197	        await fs.remove(skfDir);
198	      }
199	      s.stop('SKF module removed');
200	
201	      // Remove manifest
202	      const manifestPath = path.join(projectDir, MANIFEST_DIR, MANIFEST_FILE);
203	      if (await fs.pathExists(manifestPath)) {
204	        await fs.remove(manifestPath);
205	      }
206	      // Clean empty _bmad/_config/ and _bmad/ if we were the only occupant
207	      await removeEmptyDir(path.join(projectDir, MANIFEST_DIR));
208	      await removeEmptyDir(path.join(projectDir, '_bmad'));
209	
210	      outro('SKF uninstalled successfully.');
211	
212	      process.exit(0);
213	    } catch (error) {
214	      console.error(chalk.red('\nUninstall failed:'), error.message);
215	      process.exit(1);
216	    }
217	  },
218	};
