1	// Zod schema definition for *.agent.yaml files
2	const assert = require('node:assert');
3	const { z } = require('zod');
4	
5	const COMMAND_TARGET_KEYS = ['workflow', 'validate-workflow', 'exec', 'action', 'tmpl', 'data'];
6	const TRIGGER_PATTERN = /^[a-z0-9]+(?:-[a-z0-9]+)*$/;
7	const COMPOUND_TRIGGER_PATTERN = /^([A-Z]{1,3}) or fuzzy match on ([a-z0-9]+(?:-[a-z0-9]+)*)$/;
8	
9	/**
10	 * Derive the expected shortcut from a kebab-case trigger.
11	 * - Single word: first letter (e.g., "help" → "H")
12	 * - Multi-word: first letter of first two words (e.g., "tech-spec" → "TS")
13	 * @param {string} kebabTrigger The kebab-case trigger name.
14	 * @returns {string} The expected uppercase shortcut.
15	 */
16	function deriveShortcutFromKebab(kebabTrigger) {
17	  const words = kebabTrigger.split('-');
18	  if (words.length === 1) {
19	    return words[0][0].toUpperCase();
20	  }
21	  return (words[0][0] + words[1][0]).toUpperCase();
22	}
23	
24	/**
25	 * Parse and validate a compound trigger string.
26	 * Format: "<SHORTCUT> or fuzzy match on <kebab-case>"
27	 * @param {string} triggerValue The trigger string to parse.
28	 * @returns {{ valid: boolean, shortcut?: string, kebabTrigger?: string, error?: string }}
29	 */
30	function parseCompoundTrigger(triggerValue) {
31	  const match = COMPOUND_TRIGGER_PATTERN.exec(triggerValue);
32	  if (!match) {
33	    return { valid: false, error: 'invalid compound trigger format' };
34	  }
35	
36	  const [, shortcut, kebabTrigger] = match;
37	
38	  return { valid: true, shortcut, kebabTrigger };
39	}
40	
41	// Public API ---------------------------------------------------------------
42	
43	/**
44	 * Validate an agent YAML payload against the schema derived from its file location.
45	 * Exposed as the single public entry point, so callers do not reach into schema internals.
46	 *
47	 * @param {string} filePath Path to the agent file (used to infer module scope).
48	 * @param {unknown} agentYaml Parsed YAML content.
49	 * @returns {import('zod').SafeParseReturnType<unknown, unknown>} SafeParse result.
50	 */
51	function validateAgentFile(filePath, agentYaml) {
52	  const expectedModule = deriveModuleFromPath(filePath);
53	  const schema = agentSchema({ module: expectedModule });
54	  return schema.safeParse(agentYaml);
55	}
56	
57	/**
58	 * Validate a bmad-skill-manifest.yaml payload.
59	 *
60	 * @param {string} filePath Path to the manifest file.
61	 * @param {unknown} manifestYaml Parsed YAML content.
62	 * @returns {import('zod').SafeParseReturnType<unknown, unknown>} SafeParse result.
63	 */
64	function validateManifestFile(filePath, manifestYaml) {
65	  return manifestSchema.safeParse(manifestYaml);
66	}
67	
68	const manifestSchema = z
69	  .object({
70	    type: z.enum(['agent', 'workflow', 'tool'], {
71	      errorMap: () => ({ message: 'type must be one of: agent, workflow, tool' }),
72	    }),
73	    name: createNonEmptyString('name'),
74	    displayName: createNonEmptyString('displayName').optional(),
75	    title: createNonEmptyString('title').optional(),
76	    icon: z.string().optional(),
77	    capabilities: z.string().optional(),
78	    role: createNonEmptyString('role').optional(),
79	    identity: createNonEmptyString('identity').optional(),
80	    communicationStyle: createNonEmptyString('communicationStyle').optional(),
81	    principles: createNonEmptyString('principles').optional(),
82	    module: createNonEmptyString('module'),
83	  })
84	  .strict();
85	
86	module.exports = { validateAgentFile, validateManifestFile };
87	
88	// Internal helpers ---------------------------------------------------------
89	
90	/**
91	 * Build a Zod schema for validating a single agent definition.
92	 * The schema is generated per call so module-scoped agents can pass their expected
93	 * module slug while core agents leave it undefined.
94	 *
95	 * @param {Object} [options]
96	 * @param {string|null|undefined} [options.module] Module slug for module agents; omit or null for core agents.
97	 * @returns {import('zod').ZodSchema} Configured Zod schema instance.
98	 */
99	function agentSchema(options = {}) {
100	  const expectedModule = normalizeModuleOption(options.module);
101	
102	  return (
103	    z
104	      .object({
105	        agent: buildAgentSchema(expectedModule),
106	      })
107	      .strict()
108	      // Refinement: enforce trigger format and uniqueness rules after structural checks.
109	      .superRefine((value, ctx) => {
110	        const seenTriggers = new Set();
111	
112	        let index = 0;
113	        for (const item of value.agent.menu) {
114	          // Handle legacy format with trigger field
115	          if (item.trigger) {
116	            const triggerValue = item.trigger;
117	            let canonicalTrigger = triggerValue;
118	
119	            // Check if it's a compound trigger (contains " or ")
120	            if (triggerValue.includes(' or ')) {
121	              const result = parseCompoundTrigger(triggerValue);
122	              if (!result.valid) {
123	                ctx.addIssue({
124	                  code: 'custom',
125	                  path: ['agent', 'menu', index, 'trigger'],
126	                  message: `agent.menu[].trigger compound format error: ${result.error}`,
127	                });
128	                return;
129	              }
130	
131	              // Validate that shortcut matches description brackets
132	              const descriptionMatch = item.description?.match(/^\[([A-Z]{1,3})\]/);
133	              if (!descriptionMatch) {
134	                ctx.addIssue({
135	                  code: 'custom',
136	                  path: ['agent', 'menu', index, 'description'],
137	                  message: `agent.menu[].description must start with [SHORTCUT] where SHORTCUT matches the trigger shortcut "${result.shortcut}"`,
138	                });
139	                return;
140	              }
141	
142	              const descriptionShortcut = descriptionMatch[1];
143	              if (descriptionShortcut !== result.shortcut) {
144	                ctx.addIssue({
145	                  code: 'custom',
146	                  path: ['agent', 'menu', index, 'description'],
147	                  message: `agent.menu[].description shortcut "[${descriptionShortcut}]" must match trigger shortcut "${result.shortcut}"`,
148	                });
149	                return;
150	              }
151	
152	              canonicalTrigger = result.kebabTrigger;
153	            } else if (!TRIGGER_PATTERN.test(triggerValue)) {
154	              ctx.addIssue({
155	                code: 'custom',
156	                path: ['agent', 'menu', index, 'trigger'],
157	                message: 'agent.menu[].trigger must be kebab-case (lowercase words separated by hyphen)',
158	              });
159	              return;
160	            }
161	
162	            if (seenTriggers.has(canonicalTrigger)) {
163	              ctx.addIssue({
164	                code: 'custom',
165	                path: ['agent', 'menu', index, 'trigger'],
166	                message: `agent.menu[].trigger duplicates "${canonicalTrigger}" within the same agent`,
167	              });
168	              return;
169	            }
170	
171	            seenTriggers.add(canonicalTrigger);
172	          }
173	          // Handle multi format with triggers array (new format)
174	          else if (item.triggers && Array.isArray(item.triggers)) {
175	            for (const [triggerIndex, triggerItem] of item.triggers.entries()) {
176	              let triggerName = null;
177	
178	              // Extract trigger name from all three formats
179	              if (triggerItem.trigger) {
180	                // Format 1: Simple flat format with trigger field
181	                triggerName = triggerItem.trigger;
182	              } else {
183	                // Format 2a or 2b: Object-key format
184	                const keys = Object.keys(triggerItem);
185	                if (keys.length === 1 && keys[0] !== 'trigger') {
186	                  triggerName = keys[0];
187	                }
188	              }
189	
190	              if (triggerName) {
191	                if (!TRIGGER_PATTERN.test(triggerName)) {
192	                  ctx.addIssue({
193	                    code: 'custom',
194	                    path: ['agent', 'menu', index, 'triggers', triggerIndex],
195	                    message: `agent.menu[].triggers[] must be kebab-case (lowercase words separated by hyphen) - got "${triggerName}"`,
196	                  });
197	                  return;
198	                }
199	
200	                if (seenTriggers.has(triggerName)) {
201	                  ctx.addIssue({
202	                    code: 'custom',
203	                    path: ['agent', 'menu', index, 'triggers', triggerIndex],
204	                    message: `agent.menu[].triggers[] duplicates "${triggerName}" within the same agent`,
205	                  });
206	                  return;
207	                }
208	
209	                seenTriggers.add(triggerName);
210	              }
211	            }
212	          }
213	
214	          index += 1;
215	        }
216	      })
217	      // Refinement: suggest conversational_knowledge when discussion is true
218	      .superRefine((value, ctx) => {
219	        if (value.agent.discussion === true && !value.agent.conversational_knowledge) {
220	          ctx.addIssue({
221	            code: 'custom',
222	            path: ['agent', 'conversational_knowledge'],
223	            message: 'It is recommended to include conversational_knowledge when discussion is true',
224	          });
225	        }
226	      })
227	  );
228	}
229	
230	/**
231	 * Assemble the full agent schema using the module expectation provided by the caller.
232	 * @param {string|null} expectedModule Trimmed module slug or null for core agents.
233	 */
234	function buildAgentSchema(expectedModule) {
235	  return z
236	    .object({
237	      metadata: buildMetadataSchema(expectedModule),
238	      persona: buildPersonaSchema(),
239	      critical_actions: z.array(createNonEmptyString('agent.critical_actions[]')).optional(),
240	      menu: z.array(buildMenuItemSchema()).min(1, { message: 'agent.menu must include at least one entry' }),
241	      prompts: z.array(buildPromptSchema()).optional(),
242	      webskip: z.boolean().optional(),
243	      discussion: z.boolean().optional(),
244	      conversational_knowledge: z.array(z.object({}).passthrough()).min(1).optional(),
245	    })
246	    .strict();
247	}
248	
249	/**
250	 * Validate metadata shape.
251	 * @param {string|null} expectedModule Trimmed module slug or null when core agent metadata is expected.
252	 * Note: Module field is optional and can be any value - no validation against path.
253	 */
254	function buildMetadataSchema(expectedModule) {
255	  const schemaShape = {
256	    id: createNonEmptyString('agent.metadata.id'),
257	    name: createNonEmptyString('agent.metadata.name'),
258	    title: createNonEmptyString('agent.metadata.title'),
259	    icon: createNonEmptyString('agent.metadata.icon'),
260	    module: createNonEmptyString('agent.metadata.module').optional(),
261	    hasSidecar: z.boolean(),
262	    'sidecar-folder': createNonEmptyString('agent.metadata.sidecar-folder').optional(),
263	    'sidecar-path': createNonEmptyString('agent.metadata.sidecar-path').optional(),
264	  };
265	
266	  return z.object(schemaShape).strict();
267	}
268	
269	function buildPersonaSchema() {
270	  return z
271	    .object({
272	      role: createNonEmptyString('agent.persona.role'),
273	      identity: createNonEmptyString('agent.persona.identity'),
274	      communication_style: createNonEmptyString('agent.persona.communication_style'),
275	      principles: z.union([
276	        createNonEmptyString('agent.persona.principles'),
277	        z
278	          .array(createNonEmptyString('agent.persona.principles[]'))
279	          .min(1, { message: 'agent.persona.principles must include at least one entry' }),
280	      ]),
281	    })
282	    .strict();
283	}
284	
285	function buildPromptSchema() {
286	  return z
287	    .object({
288	      id: createNonEmptyString('agent.prompts[].id'),
289	      content: z.string().refine((value) => value.trim().length > 0, {
290	        message: 'agent.prompts[].content must be a non-empty string',
291	      }),
292	      description: createNonEmptyString('agent.prompts[].description').optional(),
293	    })
294	    .strict();
295	}
296	
297	/**
298	 * Schema for individual menu entries ensuring they are actionable.
299	 * Supports both legacy format and new multi format.
300	 */
301	function buildMenuItemSchema() {
302	  // Legacy menu item format
303	  const legacyMenuItemSchema = z
304	    .object({
305	      trigger: createNonEmptyString('agent.menu[].trigger'),
306	      description: createNonEmptyString('agent.menu[].description'),
307	      workflow: createNonEmptyString('agent.menu[].workflow').optional(),
308	      'workflow-install': createNonEmptyString('agent.menu[].workflow-install').optional(),
309	      'validate-workflow': createNonEmptyString('agent.menu[].validate-workflow').optional(),
310	      exec: createNonEmptyString('agent.menu[].exec').optional(),
311	      action: createNonEmptyString('agent.menu[].action').optional(),
312	      tmpl: createNonEmptyString('agent.menu[].tmpl').optional(),
313	      data: z.string().optional(),
314	      checklist: createNonEmptyString('agent.menu[].checklist').optional(),
315	      document: createNonEmptyString('agent.menu[].document').optional(),
316	      'ide-only': z.boolean().optional(),
317	      'web-only': z.boolean().optional(),
318	      discussion: z.boolean().optional(),
319	    })
320	    .strict()
321	    .superRefine((value, ctx) => {
322	      const hasCommandTarget = COMMAND_TARGET_KEYS.some((key) => {
323	        const commandValue = value[key];
324	        return typeof commandValue === 'string' && commandValue.trim().length > 0;
325	      });
